    if (N == 1) {
    result[0] = data[0];
    } else {
    Complex[] fe = new Complex[N/2];
    Complex[] fo = new Complex[N/2];
    for (int i = 0; i < N/2; i++) {
    fe[i] = data[2*i];
    fo[i] = data[2*i+1];
    }
    Complex[] Fe = transform(fe, N / 2);
    Complex[] Fo = transform(fo, N / 2);
